package com.esoterica.game.api\n\nimport io.micronaut.http.*\nimport io.micronaut.http.annotation.*\nimport io.micronaut.http.server.exceptions.ExceptionHandler\nimport jakarta.inject.Singleton\n\n@Singleton\n@Produces(MediaType.APPLICATION_JSON)\nclass GlobalExceptionHandler : ExceptionHandler<RuntimeException, HttpResponse<Any>> {\n    override fun handle(req: HttpRequest<*>, e: RuntimeException) = HttpResponse.serverError(mapOf("error" to e.message))\n}\n